export async function loadRegistry(): Promise<Registry> {
  const path = join(process.cwd(), 'src/bricks/registry.json')
  const data = await fs.readFile(path, 'utf-8')
  return JSON.parse(data)
}

export async function updateRegistry(registry: Registry): Promise<void> {
  const path = join(process.cwd(), 'src/bricks/registry.json')
  await fs.writeFile(path, JSON.stringify(registry, null, 2))
}

export async function addBrickToRegistry(brickId: string): Promise<void> {
  const registry = await loadRegistry()
  const maxOrder = Math.max(...registry.bricks.map(b => b.order), -1)
  registry.bricks.push({ id: brickId, enabled: true, order: maxOrder + 1 })
  await updateRegistry(registry)
}

export async function removeBrickFromRegistry(brickId: string): Promise<void> {
  const registry = await loadRegistry()
  registry.bricks = registry.bricks.filter(b => b.id !== brickId)
  await updateRegistry(registry)
}

export async function toggleBrickEnabled(brickId: string, enabled: boolean): Promise<void> {
  const registry = await loadRegistry()
  const brick = registry.bricks.find(b => b.id === brickId)
  if (brick) brick.enabled = enabled
  await updateRegistry(registry)
}

