import { NextRequest, NextResponse } from 'next/server'
import * as cheerio from 'cheerio'

const FINNHUB_API_KEY = process.env.FINNHUB_API_KEY

async function fetchUSNews(ticker: string): Promise<NewsArticle[]> {
  const to = new Date().toISOString().split('T')[0]
  const from = new Date(Date.now() - 30*24*60*60*1000).toISOString().split('T')[0]

  const url = `https://finnhub.io/api/v1/company-news?symbol=${ticker}&from=${from}&to=${to}&token=${FINNHUB_API_KEY}`
  const response = await fetch(url)
  const data = await response.json()

  return data.map((item: any) => ({
    date: new Date(item.datetime * 1000).toISOString(),
    headline: item.headline,
    source: item.source,
    url: item.url,
    sentiment: item.sentiment // Basic sentiment from Finnhub
  }))
}

async function fetchKRNews(ticker: string): Promise<NewsArticle[]> {
  const stockCode = ticker.replace(/\.(KS|KQ)$/, '')
  const url = `https://finance.naver.com/item/news_news.naver?code=${stockCode}`

  const response = await fetch(url)
  const html = await response.text()
  const $ = cheerio.load(html)

  const articles: NewsArticle[] = []
  $('.title').each((_, elem) => {
    const headline = $(elem).text().trim()
    const url = $(elem).find('a').attr('href')
    const date = $(elem).closest('tr').find('.date').text()

    if (headline && url) {
      articles.push({
        date,
        headline,
        source: 'Naver Finance',
        url: `https://finance.naver.com${url}`,
        sentiment: undefined // Basic keyword sentiment could be added
      })
    }
  })

  return articles
}

export async function GET(
