export function BrickRenderer({ ticker }: { ticker: string }) {
  const [bricks, setBricks] = useState<BrickModule[]>([])
  const [loading, setLoading] = useState(true)
  const market = ticker.includes('.KS') || ticker.includes('.KQ') ? 'KR' : 'US'

  useEffect(() => {
    async function loadBricks() {
      const registry = await fetch('/api/bricks/registry').then(r => r.json())
      const enabledBricks = registry.bricks
        .filter((b: RegistryEntry) => b.enabled)
        .sort((a: RegistryEntry, b: RegistryEntry) => a.order - b.order)

      const modules = await Promise.all(
        enabledBricks.map(async (entry: RegistryEntry) => {
          try {
            const brick = await import(`@/bricks/${entry.id}`)
            return brick.default
          } catch (error) {
            console.error(`Failed to load brick ${entry.id}:`, error)
            return null
          }
        })
      )

      setBricks(modules.filter(Boolean))
      setLoading(false)
    }

    loadBricks()
  }, [ticker])

  if (loading) return <div>Loading bricks...</div>

  return (
    <div className="space-y-6">
      {bricks.map((brick, index) => (
        <ErrorBoundary
          key={brick.manifest.id}
          fallbackRender={({ error }) => <BrickErrorFallback error={error} brickId={brick.manifest.id} />}
        >
          <brick.Component ticker={ticker} market={market} />
        </ErrorBoundary>
      ))}
    </div>
  )
}

