}

export function evaluateFormula(formula: string, data: Record<string, number>): number {
  // Safe formula evaluation using Function constructor with data context
  // Only allow mathematical operations and data field references
  // No eval() for security
  try {
    const func = new Function(...Object.keys(data), `return ${formula}`)
    return func(...Object.values(data))
  } catch (error) {
    throw new Error('Invalid formula')
  }
}

