import { NextRequest, NextResponse } from 'next/server'
import Anthropic from '@anthropic-ai/sdk'
import fs from 'fs/promises'
import path from 'path'
import { addBrickToRegistry } from '@/lib/brick-registry'

const anthropic = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY
})

const SYSTEM_PROMPT = `You are a code generation AI that creates modular "Brick" components for a stock analysis application.

Brick Architecture:
- Each Brick is a self-contained directory under src/bricks/{brick-id}/
- Required files: manifest.json, component.tsx, index.ts
- Optional files: api.ts, calculations.ts
- Component receives props: { ticker: string, market: 'KR' | 'US', data?: Record<string, unknown> }
- Must use shadcn/ui components (@/components/ui/*)
- Must be independent (no imports from other Bricks)
- TypeScript strict mode

When given a user prompt, generate:
1. A unique kebab-case brick-id
2. manifest.json following the BrickManifest interface
3. component.tsx with a React component that implements the requested functionality
4. index.ts barrel export
5. Any additional files needed (api.ts for data fetching, calculations.ts for formulas)

Respond with a JSON object:
{
  "brickId": "unique-brick-id",
  "files": {
    "manifest.json": "<file content>",
    "component.tsx": "<file content>",
    "index.ts": "<file content>",
    "api.ts": "<file content (optional)>",
    "calculations.ts": "<file content (optional)>"
  }
}`

export async function POST(request: NextRequest) {
  try {
    const { prompt, ticker } = await request.json()

    if (!prompt) {
      return NextResponse.json({ error: 'Prompt required' }, { status: 400 })
    }

    const message = await anthropic.messages.create({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 4000,
      system: SYSTEM_PROMPT,
      messages: [{
        role: 'user',
        content: `Create a Brick for: ${prompt}\n\nTarget ticker: ${ticker}`
      }]
    })

    const responseText = message.content[0].type === 'text' ? message.content[0].text : ''
    const jsonMatch = responseText.match(/\{[\s\S]*\}/)
    if (!jsonMatch) {
      throw new Error('Invalid AI response format')
    }

    const { brickId, files } = JSON.parse(jsonMatch[0])

    // Write files to src/bricks/{brickId}/
    const brickDir = path.join(process.cwd(), 'src/bricks', brickId)
    await fs.mkdir(brickDir, { recursive: true })

    for (const [filename, content] of Object.entries(files)) {
      await fs.writeFile(path.join(brickDir, filename), content as string)
    }

    // Update registry
    await addBrickToRegistry(brickId)

    // Parse manifest for brick name
    const manifest = JSON.parse(files['manifest.json'] as string)

    return NextResponse.json({
      success: true,
      brickId,
      brickName: manifest.name
    })
  } catch (error) {
    console.error('Brick creation error:', error)
    return NextResponse.json({ error: 'Failed to create brick' }, { status: 500 })
  }
}

