  const router = useRouter()

  useEffect(() => {
    async function loadBricks() {
      const registry = await fetch('/api/bricks/registry').then(r => r.json())

      // Load manifests for each brick
      const bricksWithManifest = await Promise.all(
        registry.bricks.map(async (entry: any) => {
          try {
            const manifest = await import(`@/bricks/${entry.id}/manifest.json`)
            return { ...entry, manifest: manifest.default }
          } catch (error) {
            return { ...entry, manifest: { name: entry.id, author: 'unknown', category: 'unknown' } }
          }
        })
      )

      setBricks(bricksWithManifest.sort((a, b) => a.order - b.order))
    }
    loadBricks()
  }, [])

  const handleToggle = async (brickId: string, enabled: boolean) => {
    await fetch('/api/bricks/registry', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ brickId, enabled })
    })

    setBricks(prev => prev.map(b => b.id === brickId ? { ...b, enabled } : b))
    router.refresh()
  }

  const handleDelete = async (brickId: string) => {
