import { NextRequest, NextResponse } from 'next/server'
import fs from 'fs/promises'
import path from 'path'
import { removeBrickFromRegistry, loadRegistry } from '@/lib/brick-registry'

export async function DELETE(request: NextRequest) {
  try {
    const { brickId } = await request.json()

    // Verify brick exists and is not a system brick
    const manifestPath = path.join(process.cwd(), `src/bricks/${brickId}/manifest.json`)
    const manifestData = await fs.readFile(manifestPath, 'utf-8')
    const manifest = JSON.parse(manifestData)

    if (manifest.author === 'system') {
      return NextResponse.json({ error: 'Cannot delete system bricks' }, { status: 403 })
    }

    // Delete directory
    const brickDir = path.join(process.cwd(), 'src/bricks', brickId)
    await fs.rm(brickDir, { recursive: true, force: true })

    // Remove from registry
    await removeBrickFromRegistry(brickId)

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('Brick deletion error:', error)
    return NextResponse.json({ error: 'Failed to delete brick' }, { status: 500 })
  }
}
